import axios from 'axios';

const API_URL = process.env.EXPO_PUBLIC_API_URL;

export const api = axios.create({
  baseURL: API_URL,
  timeout: 5000,
  headers: {
    'Content-Type': 'application/json',
  },
});

import React, { useEffect } from 'react';
import { View, FlatList, StyleSheet, ActivityIndicator, Text } from 'react-native';
import { EventCard } from '../components/EventCard';
import { useEvents } from '../hooks/useEvents';
import { useLocation } from '../hooks/useLocation';

export default function HomeScreen({ navigation }: any) {
  const { location } = useLocation();
  const { events, loadNearbyEvents, isLoadingEvents } = useEvents();

  useEffect(() => {
    if (location) {
      loadNearbyEvents(location.coords.latitude, location.coords.longitude);
    }
  }, [location, loadNearbyEvents]);

  if (isLoadingEvents && events.length === 0) {
    return (
      <View style={styles.center}>
        <ActivityIndicator size="large" color="#1E90FF" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.header}>Eventos cerca de ti</Text>
      <FlatList
        data={events}
        keyExtractor={(item) => item.id.toString()}
        renderItem={({ item }) => (
          <EventCard 
            event={item} 
            onPress={() => navigation.navigate('EventDetail', { event: item })} 
          />
        )}
        contentContainerStyle={styles.list}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#F5F5F5' },
  center: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  header: { fontSize: 22, fontWeight: 'bold', margin: 16, color: '#333' },
  list: { paddingBottom: 20 },
});

import React from 'react';
import { View, Text, StyleSheet, Button } from 'react-native';

export default function EventDetailScreen({ route, navigation }: any) {
  const { event } = route.params;

  return (
    <View style={styles.container}>
      <Text style={styles.title}>{event.name}</Text>

      <View style={styles.card}>
        <Text style={styles.info}>📅 Fecha: {event.date}</Text>
        {event.category && <Text style={styles.info}>🏷️ Categoría: {event.category}</Text>}
        {event.distance && <Text style={styles.info}>📍 Distancia: {event.distance}</Text>}

        <View style={styles.mapPlaceholder}>
          <Text style={styles.placeholderText}>Aquí puedes añadir un mini mapa del evento</Text>
        </View>
      </View>

      <Button 
        title="Volver al Mapa" 
        onPress={() => navigation.navigate('Map')} 
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 16, backgroundColor: '#F5F5F5' },
  title: { fontSize: 26, fontWeight: 'bold', marginBottom: 16, color: '#333' },
  card: { backgroundColor: '#FFF', padding: 20, borderRadius: 12, elevation: 3, marginBottom: 20 },
  info: { fontSize: 16, marginBottom: 10, color: '#555' },
  mapPlaceholder: { height: 150, backgroundColor: '#E0E0E0', justifyContent: 'center', alignItems: 'center', borderRadius: 8, marginTop: 10 },
  placeholderText: { color: '#888' }
});
